# --- begin: scripts/lib/ui/styles.sh ---
# shellcheck shell=bash
# shellcheck disable=SC2034

init_output_styles() {
  style_reset=""
  style_step=""
  style_detail=""
  style_success=""
  style_warning=""
  style_error=""
  style_muted=""

  if [[ -t 1 && -z "${NO_COLOR:-}" ]]; then
    style_reset=$'\033[0m'
    style_step=$'\033[1;36m'
    style_detail=$'\033[0;37m'
    style_success=$'\033[1;32m'
    style_warning=$'\033[1;33m'
    style_error=$'\033[1;31m'
    style_muted=$'\033[0;90m'
  fi
}

style_text() {
  local style="$1"
  local text="$2"

  if [[ -z "$style" ]]; then
    printf '%s' "$text"
    return 0
  fi

  printf '%s%s%s' "$style" "$text" "$style_reset"
}
# --- end: scripts/lib/ui/styles.sh ---

# --- begin: scripts/lib/ui/logging.sh ---
# shellcheck shell=bash

init_logging() {
  if [[ "${POSTINSTALL_LOG_INITIALIZED:-0}" == "1" ]]; then
    return
  fi

  mkdir -p "$(dirname "$LOG_FILE")"
  touch "$LOG_FILE"

  export POSTINSTALL_LOG_FILE="$LOG_FILE"
  export POSTINSTALL_LOG_INITIALIZED=1

  exec > >(tee -a "$LOG_FILE") 2>&1
}

write_log_only() {
  if [[ "${POSTINSTALL_LOG_INITIALIZED:-0}" != "1" ]]; then
    return 0
  fi

  printf '%s\n' "$1" >>"$LOG_FILE"
}
# --- end: scripts/lib/ui/logging.sh ---

# --- begin: scripts/lib/ui/notice.sh ---
# shellcheck shell=bash

emit_notice() {
  local symbol="$1"
  local style="$2"
  local message="$3"
  local line_prefix=""

  if [[ "$step_open" == "1" ]]; then
    line_prefix="│  "
  fi

  printf '%s%s %s\n' "$line_prefix" "$(style_text "$style" "$symbol")" "$message"
}

set_step_total() {
  step_total="$1"
}

increment_step_total() {
  step_total=$((step_total + ${1:-1}))
}

announce_step() {
  local title="$1"
  local header=""

  close_step_block
  step_counter=$((step_counter + 1))
  if (( step_total > 0 )); then
    header=$(printf 'Etapa %02d/%02d • %s' "$step_counter" "$step_total" "$title")
  else
    header=$(printf 'Etapa %02d • %s' "$step_counter" "$title")
  fi
  echo
  printf '%s %s\n' "$(style_text "$style_step" "╭─")" "$(style_text "$style_step" "$header")"
  step_open=1
}

announce_detail() {
  if [[ "$STEP_OUTPUT_ONLY" == "1" ]]; then
    if [[ "$1" == *"Etapa ignorada."* || "$1" == Instalando\ via\ pacman:* || "$1" == Instalando\ via\ AUR:* ]]; then
      write_log_only "$1"
      return 0
    fi
    printf '│  %s %s\n' "$(style_text "$style_detail" "•")" "$1"
    return 0
  fi

  printf '│  %s %s\n' "$(style_text "$style_detail" "•")" "$1"
}

announce_warning() {
  emit_notice "!" "$style_warning" "$1"
}

announce_error() {
  emit_notice "x" "$style_error" "$1"
}

announce_prompt() {
  emit_notice "?" "$style_step" "$1"
}

close_step_block() {
  if [[ "$step_open" != "1" ]]; then
    return 0
  fi

  style_text "$style_muted" "╰─"
  printf '\n'
  step_open=0
}
# --- end: scripts/lib/ui/notice.sh ---

# --- begin: scripts/lib/ui/summary-primitives.sh ---
# shellcheck shell=bash

print_summary_section() {
  local title="$1"
  echo "│"
  printf '│  %s\n' "$(style_text "$style_step" "$title")"
}

print_summary_item() {
  local label="$1"
  local value="$2"
  local label_length=0
  local padding_width=22

  label_length="$(printf '%s' "$label" | wc -m | tr -d '[:space:]')"
  if [[ -z "$label_length" ]]; then
    label_length=0
  fi
  if (( label_length < padding_width )); then
    printf '│  %s %s%*s %s\n' "$(style_text "$style_detail" "•")" "$label" "$((padding_width - label_length))" "" "$value"
    return 0
  fi

  printf '│  %s %s %s\n' "$(style_text "$style_detail" "•")" "$label" "$value"
}
# --- end: scripts/lib/ui/summary-primitives.sh ---

# --- begin: scripts/lib/pipeline.sh ---
# shellcheck shell=bash

PIPELINE_STEP_IDS=()
PIPELINE_STEP_MODES=()
PIPELINE_STEP_TITLES=()
PIPELINE_STEP_FUNCTIONS=()
PIPELINE_STEP_COUNT_FLAGS=()
PIPELINE_STEP_ARGS=()

pipeline_reset() {
  PIPELINE_STEP_IDS=()
  PIPELINE_STEP_MODES=()
  PIPELINE_STEP_TITLES=()
  PIPELINE_STEP_FUNCTIONS=()
  PIPELINE_STEP_COUNT_FLAGS=()
  PIPELINE_STEP_ARGS=()
}

pipeline_add_step() {
  local step_id="$1"
  local step_mode="$2"
  local step_title="$3"
  local step_function="$4"
  local step_count_flag="${5:-1}"
  local step_args="${6:-}"

  PIPELINE_STEP_IDS+=("$step_id")
  PIPELINE_STEP_MODES+=("$step_mode")
  PIPELINE_STEP_TITLES+=("$step_title")
  PIPELINE_STEP_FUNCTIONS+=("$step_function")
  PIPELINE_STEP_COUNT_FLAGS+=("$step_count_flag")
  PIPELINE_STEP_ARGS+=("$step_args")
}

pipeline_step_matches_mode() {
  local step_mode="$1"
  local execution_mode="$2"

  [[ "$step_mode" == "all" || "$step_mode" == "$execution_mode" ]]
}

pipeline_contains_step_id() {
  local step_id="$1"
  local existing_id

  for existing_id in "${PIPELINE_STEP_IDS[@]}"; do
    [[ "$existing_id" == "$step_id" ]] && return 0
  done

  return 1
}

pipeline_count_steps_for_mode() {
  local execution_mode="$1"
  local total=0
  local index

  for index in "${!PIPELINE_STEP_IDS[@]}"; do
    if ! pipeline_step_matches_mode "${PIPELINE_STEP_MODES[$index]}" "$execution_mode"; then
      continue
    fi

    [[ "${PIPELINE_STEP_COUNT_FLAGS[$index]:-0}" == "1" ]] || continue
    total=$((total + 1))
  done

  printf '%s\n' "$total"
}

run_pipeline_steps() {
  local execution_mode="$1"
  local result_handler="${2:-}"
  local index=0
  local step_title
  local step_function
  local step_count_flag
  local step_args

  while (( index < ${#PIPELINE_STEP_IDS[@]} )); do
    if ! pipeline_step_matches_mode "${PIPELINE_STEP_MODES[$index]}" "$execution_mode"; then
      index=$((index + 1))
      continue
    fi

    step_title="${PIPELINE_STEP_TITLES[$index]}"
    step_function="${PIPELINE_STEP_FUNCTIONS[$index]}"
    step_count_flag="${PIPELINE_STEP_COUNT_FLAGS[$index]:-0}"
    step_args="${PIPELINE_STEP_ARGS[$index]}"

    if [[ "$step_count_flag" == "1" && -n "$step_title" ]]; then
      announce_step "$step_title"
    fi

    if [[ -n "$step_args" ]]; then
      "$step_function" "$step_args"
    else
      "$step_function"
    fi

    if [[ -n "$result_handler" ]]; then
      "$result_handler"
    fi

    index=$((index + 1))
  done
}
# --- end: scripts/lib/pipeline.sh ---

# --- begin: scripts/lib/step-registry.sh ---
# shellcheck shell=bash
# shellcheck disable=SC2034

STEP_DEFINITION_IDS=()
declare -Ag STEP_DEFINITION_MODES=()
declare -Ag STEP_DEFINITION_TITLES=()
declare -Ag STEP_DEFINITION_FUNCTIONS=()
declare -Ag STEP_DEFINITION_COUNT_FLAGS=()

register_step_definition() {
  local step_id="$1"
  shift

  local assignment=""
  local step_mode=""
  local step_title=""
  local step_function=""
  local count_for_progress=""

  for assignment in "$@"; do
    case "$assignment" in
      mode=*)
        step_mode="${assignment#*=}"
        ;;
      title=*)
        step_title="${assignment#*=}"
        ;;
      function=*)
        step_function="${assignment#*=}"
        ;;
      count_for_progress=*)
        count_for_progress="${assignment#*=}"
        ;;
      *)
        printf 'Erro: metadado de etapa desconhecido para %s: %s\n' "$step_id" "$assignment" >&2
        return 1
        ;;
    esac
  done

  if [[ -z "$step_id" || -z "$step_mode" || -z "$step_function" || -z "$count_for_progress" ]]; then
    printf 'Erro: etapa incompleta: %s\n' "${step_id:-indefinida}" >&2
    return 1
  fi

  STEP_DEFINITION_IDS+=("$step_id")
  STEP_DEFINITION_MODES["$step_id"]="$step_mode"
  STEP_DEFINITION_TITLES["$step_id"]="$step_title"
  STEP_DEFINITION_FUNCTIONS["$step_id"]="$step_function"
  STEP_DEFINITION_COUNT_FLAGS["$step_id"]="$count_for_progress"
}

step_definition_mode() {
  printf '%s\n' "${STEP_DEFINITION_MODES[$1]:-}"
}

step_definition_title() {
  printf '%s\n' "${STEP_DEFINITION_TITLES[$1]:-}"
}

step_definition_function() {
  printf '%s\n' "${STEP_DEFINITION_FUNCTIONS[$1]:-}"
}

step_definition_count_flag() {
  printf '%s\n' "${STEP_DEFINITION_COUNT_FLAGS[$1]:-0}"
}

append_registered_step() {
  local step_id="$1"
  local step_args="${2:-}"
  local step_mode=""
  local step_title=""
  local step_function=""
  local step_count_flag="0"

  step_mode="$(step_definition_mode "$step_id")"
  step_title="$(step_definition_title "$step_id")"
  step_function="$(step_definition_function "$step_id")"
  step_count_flag="$(step_definition_count_flag "$step_id")"

  [[ -n "$step_mode" && -n "$step_function" ]] || {
    printf 'Erro: etapa não registrada: %s\n' "$step_id" >&2
    return 1
  }

  pipeline_add_step "$step_id" "$step_mode" "$step_title" "$step_function" "$step_count_flag" "$step_args"
}
# --- end: scripts/lib/step-registry.sh ---

