# --- begin: scripts/lib/step-pipeline.sh ---
# shellcheck shell=bash

append_runtime_component_steps() {
  local phase="$1"
  local component_ids=()
  local component_id
  local pipeline_title=""
  local pipeline_function=""

  case "$phase" in
    pre_package)
      mapfile -t component_ids < <(component_pre_package_pipeline_ids)
      ;;
    post_package)
      mapfile -t component_ids < <(component_post_package_pipeline_ids)
      ;;
    *)
      printf 'Erro: fase de pipeline desconhecida: %s\n' "$phase" >&2
      return 1
      ;;
  esac

  for component_id in "${component_ids[@]}"; do
    pipeline_title="$(component_pipeline_title "$component_id")"
    pipeline_function="$(component_pipeline_step_function "$component_id")"
    pipeline_add_step "$component_id" "install" "$pipeline_title" "$pipeline_function" "1"
  done
}

append_runtime_install_pipeline() {
  local package_array_name="$1"
  local origin_status=0

  append_registered_step "create_directories"
  append_registered_step "relocate_home_backups"
  append_registered_step "relocate_home_repositories"
  append_registered_step "ensure_multilib"
  append_registered_step "update_system"
  append_registered_step "install_local_support_packages"
  append_runtime_component_steps "pre_package"
  append_registered_step "sync_managed_repositories"

  if target_packages_have_official_entries "$package_array_name"; then
    append_registered_step "prepare_package_installation"
    append_registered_step "install_official_packages" "$package_array_name"
  else
    origin_status=$?
    if [[ "$origin_status" != "1" ]]; then
      return 1
    fi
  fi

  if target_packages_have_aur_entries "$package_array_name"; then
    if ! pipeline_contains_step_id "prepare_package_installation"; then
      append_registered_step "prepare_package_installation"
    fi
    append_registered_step "install_aur_packages" "$package_array_name"
  else
    origin_status=$?
    if [[ "$origin_status" != "1" ]]; then
      return 1
    fi
  fi

  if pipeline_contains_step_id "prepare_package_installation"; then
    append_registered_step "finalize_package_installation"
  fi

  append_runtime_component_steps "post_package"
  append_registered_step "final_verification" "$package_array_name"
}

define_runtime_pipeline() {
  local package_array_name="$1"

  pipeline_reset
  if [[ "$DRY_RUN" == "1" ]]; then
    append_registered_step "load_configuration" "$package_array_name"
    append_registered_step "dry_run_plan" "$package_array_name"
    return 0
  fi

  append_registered_step "runtime_validate_environment"
  append_registered_step "load_configuration" "$package_array_name"

  if [[ "$CHECK_ONLY" == "1" ]]; then
    append_registered_step "check_only_verification" "$package_array_name"
  fi
}

define_bootstrap_pipeline() {
  local missing_packages_array_name="$1"

  pipeline_reset
  append_registered_step "bootstrap_validate_environment"
  append_registered_step "bootstrap_check_dependencies" "$missing_packages_array_name"

  if bootstrap_missing_packages_present "$missing_packages_array_name"; then
    append_registered_step "bootstrap_install_dependencies" "$missing_packages_array_name"
  fi

  append_registered_step "bootstrap_sync_repo"
}

bootstrap_missing_packages_present() {
  local array_name="$1"
  declare -n missing_packages="$array_name"

  (( ${#missing_packages[@]} > 0 ))
}
# --- end: scripts/lib/step-pipeline.sh ---

# --- begin: scripts/lib/process.sh ---
# shellcheck shell=bash

append_array_item() {
  local array_name="$1"
  local value="$2"
  local existing
  # shellcheck disable=SC2178
  declare -n target_array_ref="$array_name"

  for existing in "${target_array_ref[@]}"; do
    [[ "$existing" == "$value" ]] && return 0
  done

  target_array_ref+=("$value")
}

package_is_installed() {
  pacman -Q "$1" >/dev/null 2>&1
}

run_with_terminal_stdin() {
  if [[ -r /dev/tty ]]; then
    "$@" </dev/tty
    return
  fi

  "$@"
}

collect_missing_packages() {
  local array_name="$1"
  shift
  local package_name
  # shellcheck disable=SC2178
  declare -n target_array_ref="$array_name"

  target_array_ref=()
  for package_name in "$@"; do
    if ! package_is_installed "$package_name"; then
      target_array_ref+=("$package_name")
    fi
  done
}

run_log_only() {
  if [[ "$STEP_OUTPUT_ONLY" == "1" ]]; then
    "$@" </dev/null >>"$LOG_FILE" 2>&1
    return
  fi

  "$@" </dev/null 2>&1 | sed 's/^/│    /'
  return "${PIPESTATUS[0]}"
}

run_interactive_log_only() {
  if [[ "$STEP_OUTPUT_ONLY" == "1" ]]; then
    run_with_terminal_stdin "$@" >>"$LOG_FILE" 2>&1
    return
  fi

  run_with_terminal_stdin "$@" 2>&1 | sed 's/^/│    /'
  return "${PIPESTATUS[0]}"
}

retry() {
  "$@"
}

retry_log_only() {
  run_log_only "$@"
}

retry_interactive_log_only() {
  run_interactive_log_only "$@"
}
# --- end: scripts/lib/process.sh ---

# --- begin: scripts/lib/locking.sh ---
# shellcheck shell=bash

checkpoint_file() {
  printf '%s/checkpoints/%s.done\n' "$STATE_DIR" "$1"
}

has_checkpoint() {
  [[ -f "$(checkpoint_file "$1")" ]]
}

mark_checkpoint() {
  mkdir -p "$STATE_DIR/checkpoints"
  touch "$(checkpoint_file "$1")"
}

register_cleanup_path() {
  cleanup_paths+=("$1")
}

acquire_lock() {
  local existing_pid=""

  if [[ "$LOCK_HELD" == "1" ]]; then
    if [[ -f "$LOCK_DIR/pid" ]]; then
      existing_pid="$(<"$LOCK_DIR/pid")"
    fi

    if [[ -n "$existing_pid" && "$existing_pid" == "$$" ]]; then
      register_cleanup_path "$LOCK_DIR"
      return
    fi

    announce_error "Lock herdado inválido ou pertencente a outro processo."
    return 1
  fi

  mkdir -p "$STATE_DIR"
  if mkdir "$LOCK_DIR" 2>/dev/null; then
    printf '%s\n' "$$" >"$LOCK_DIR/pid"
    register_cleanup_path "$LOCK_DIR"
    export POSTINSTALL_LOCK_HELD=1
    LOCK_HELD=1
    return
  fi

  if [[ -f "$LOCK_DIR/pid" ]]; then
    existing_pid="$(<"$LOCK_DIR/pid")"
  fi

  if [[ -z "$existing_pid" ]] || ! kill -0 "$existing_pid" 2>/dev/null; then
    announce_warning "Foi detectado um lock órfão. Limpando a execução anterior."
    rm -rf -- "$LOCK_DIR"
    if mkdir "$LOCK_DIR" 2>/dev/null; then
      printf '%s\n' "$$" >"$LOCK_DIR/pid"
      register_cleanup_path "$LOCK_DIR"
      export POSTINSTALL_LOCK_HELD=1
      LOCK_HELD=1
      return
    fi
  fi

  announce_error "Já existe outra execução do script em andamento."
  if [[ -f "$LOCK_DIR/pid" ]]; then
    announce_error "PID atual do lock: $(<"$LOCK_DIR/pid")"
  fi
  return 1
}

cleanup() {
  local path

  for path in "${cleanup_paths[@]}"; do
    [[ -n "$path" ]] || continue
    rm -rf -- "$path"
  done
}
# --- end: scripts/lib/locking.sh ---

# --- begin: scripts/lib/env.sh ---
# shellcheck shell=bash

ensure_not_root() {
  if [[ "${EUID:-$(id -u)}" -eq 0 ]]; then
    announce_error "Execute este script como usuário comum, e não como root."
    return 1
  fi
}

require_command() {
  if ! command -v "$1" >/dev/null 2>&1; then
    announce_error "Comando obrigatório não encontrado: $1"
    return 1
  fi
}

canonicalize_path() {
  if ! command -v realpath >/dev/null 2>&1; then
    announce_error "Comando obrigatório não encontrado: realpath"
    return 1
  fi

  realpath -m -- "$1"
}

require_exact_path() {
  local label="$1"
  local actual_path="$2"
  local expected_path="$3"
  local resolved_actual=""
  local resolved_expected=""

  [[ -n "$actual_path" && -n "$expected_path" ]] || {
    announce_error "Caminho inválido para $label."
    return 1
  }

  resolved_actual="$(canonicalize_path "$actual_path")" || return 1
  resolved_expected="$(canonicalize_path "$expected_path")" || return 1

  if [[ "$resolved_actual" != "$resolved_expected" ]]; then
    announce_error "$label fora do caminho gerenciado esperado: $actual_path"
    announce_error "Esperado: $resolved_expected"
    return 1
  fi
}

validate_managed_paths() {
  local expected_projects_dir="$HOME/Projects"
  local expected_repositories_dir="$HOME/Repositories"
  local expected_install_dir="$expected_projects_dir/arch-postinstall-apps"
  local expected_yay_repo_dir="$expected_repositories_dir/yay"
  local expected_easyeffects_preset_dir="$HOME/EasyEffects-Preset"
  local expected_state_dir="${XDG_STATE_HOME:-$HOME/.local/state}/arch-postinstall-apps"
  local expected_lock_dir="$expected_state_dir/lock"

  require_exact_path "PROJECTS_DIR" "$PROJECTS_DIR" "$expected_projects_dir" || return 1
  require_exact_path "REPOSITORIES_DIR" "$REPOSITORIES_DIR" "$expected_repositories_dir" || return 1
  require_exact_path "INSTALL_DIR" "$INSTALL_DIR" "$expected_install_dir" || return 1
  require_exact_path "YAY_REPO_DIR" "$YAY_REPO_DIR" "$expected_yay_repo_dir" || return 1
  require_exact_path "EASY_EFFECTS_PRESET_DIR" "$EASY_EFFECTS_PRESET_DIR" "$expected_easyeffects_preset_dir" || return 1
  require_exact_path "STATE_DIR" "$STATE_DIR" "$expected_state_dir" || return 1
  require_exact_path "LOCK_DIR" "$LOCK_DIR" "$expected_lock_dir" || return 1
}

get_host_name() {
  if command -v hostname >/dev/null 2>&1; then
    hostname
    return
  fi

  if command -v hostnamectl >/dev/null 2>&1; then
    hostnamectl hostname 2>/dev/null
    return
  fi

  if [[ -f /etc/hostname ]]; then
    cat /etc/hostname
    return
  fi

  uname -n
}

sanitize_label() {
  printf '%s' "$1" | tr -cs '[:alnum:].@_-' '-'
}

is_wayland_session() {
  [[ "${XDG_SESSION_TYPE:-}" == "wayland" || -n "${WAYLAND_DISPLAY:-}" ]]
}

is_hyprland_session() {
  [[ -n "${HYPRLAND_INSTANCE_SIGNATURE:-}" ]] || \
    [[ "${XDG_CURRENT_DESKTOP:-}" == *Hyprland* ]] || \
    [[ "${DESKTOP_SESSION:-}" == "hyprland" ]]
}

is_supported_session() {
  is_wayland_session && is_hyprland_session
}

ensure_supported_session() {
  if is_supported_session; then
    return 0
  fi

  announce_error "Este script foi ajustado para Wayland com Hyprland."
  announce_error "Sessão atual: XDG_SESSION_TYPE='${XDG_SESSION_TYPE:-}', XDG_CURRENT_DESKTOP='${XDG_CURRENT_DESKTOP:-}', DESKTOP_SESSION='${DESKTOP_SESSION:-}'"
  return 1
}

ensure_arch() {
  if [[ ! -f /etc/arch-release ]]; then
    announce_error "Este script foi feito para Arch Linux."
    return 1
  fi
}

github_ssh_expected() {
  [[ "$SKIP_GITHUB_SSH" != "1" ]]
}

github_ssh_force_reconcile() {
  [[ "$EXCLUSIVE_GITHUB_SSH_KEY" == "1" || -n "$GITHUB_SSH_KEY_NAME" ]]
}
# --- end: scripts/lib/env.sh ---

# --- begin: scripts/lib/environment-validation.sh ---
# shellcheck shell=bash

validate_execution_environment_step() {
  local context_name="$1"
  local success_message="$2"

  step_result_reset

  if ! ensure_arch; then
    step_result_hard_fail "Este $context_name só pode ser executado em Arch Linux."
    return 0
  fi

  if ! ensure_supported_session; then
    step_result_hard_fail "A sessão atual não é compatível com o $context_name."
    return 0
  fi

  if ! require_command pacman; then
    step_result_hard_fail "O comando 'pacman' é obrigatório para continuar."
    return 0
  fi

  if ! require_command sudo; then
    step_result_hard_fail "O comando 'sudo' é obrigatório para continuar."
    return 0
  fi

  if [[ "${CHECK_ONLY:-0}" == "1" ]]; then
    announce_detail "Check: sudo encontrado; autenticação interativa não será solicitada."
    announce_detail "Uma execução real ainda exigirá sudo/root para pacman, systemd e arquivos de sistema."
    if declare -F operation_plan_add >/dev/null; then
      operation_plan_add \
        "check-sudo-requirement" \
        "privilege" \
        "sudo/root" \
        "Validar requisito de sudo para execução real" \
        "high" \
        "" \
        "allow" \
        "" \
        "executar novamente em terminal interativo se a instalação real precisar autenticar sudo" || true
      operation_plan_set_command "check-sudo-requirement" "sudo -v" "1"
      operation_plan_set_status "check-sudo-requirement" "skipped" "check-only: autenticação não solicitada"
    fi
    init_logging
    step_result_success "$success_message"
    return 0
  fi

  announce_prompt "Autenticando sudo..."
  if ! ops_sudo_auth; then
    step_result_hard_fail "Não foi possível autenticar o sudo."
    return 0
  fi

  init_logging
  step_result_success "$success_message"
}
# --- end: scripts/lib/environment-validation.sh ---

# --- begin: scripts/lib/ops/common.sh ---
# shellcheck shell=bash

ops_sanitize_id() {
  if declare -F sanitize_label >/dev/null; then
    sanitize_label "$1"
    return 0
  fi

  printf '%s' "$1" | tr -cs '[:alnum:].@_-' '-'
}

ops_redact_command_arg() {
  local arg="$1"

  case "$arg" in
    *token=*|*TOKEN=*|*secret=*|*SECRET=*|*password=*|*PASSWORD=*)
      printf '%s\n' "${arg%%=*}=<redacted>"
      ;;
    ghp_*|github_pat_*|glpat-*|xoxb-*|xoxp-*)
      printf '<redacted>\n'
      ;;
    *)
      printf '%s\n' "$arg"
      ;;
  esac
}

ops_command_line() {
  local command_line=""
  local part
  local rendered_part
  local quoted_part

  for part in "$@"; do
    rendered_part="$(ops_redact_command_arg "$part")"
    printf -v quoted_part '%q' "$rendered_part"
    command_line="${command_line:+$command_line }$quoted_part"
  done

  printf '%s\n' "$command_line"
}
# --- end: scripts/lib/ops/common.sh ---

# --- begin: scripts/lib/ops/privilege.sh ---
# shellcheck shell=bash

ops_sudo_auth() {
  run_with_terminal_stdin sudo -v
}
# --- end: scripts/lib/ops/privilege.sh ---

# --- begin: scripts/lib/ops/package.sh ---
# shellcheck shell=bash

declare -Ag OPS_PACMAN_OPERATION_ACTIONS=()
declare -Ag OPS_PACMAN_OPERATION_PACKAGES=()
declare -Ag OPS_AUR_OPERATION_HELPERS=()
declare -Ag OPS_AUR_OPERATION_PACKAGES=()
declare -Ag OPS_YAY_BUILD_OPERATION_DIRS=()

ops_package_planner_available() {
  declare -F operation_plan_add >/dev/null && declare -F operation_plan_execute >/dev/null
}

ops_pacman_db_lock_file() {
  printf '%s\n' "${POSTINSTALL_PACMAN_DB_LOCK_FILE:-/var/lib/pacman/db.lck}"
}

ops_pacman_db_lock_present() {
  [[ -e "$(ops_pacman_db_lock_file)" ]]
}

ops_warn_pacman_lock() {
  local lock_file

  lock_file="$(ops_pacman_db_lock_file)"
  if declare -F announce_warning >/dev/null; then
    announce_warning "Operação bloqueada: lock do pacman encontrado em $lock_file."
  fi
}

ops_block_planned_package_operation_if_locked() {
  local operation_id="$1"

  [[ "${DRY_RUN:-0}" == "1" ]] && return 1
  ops_pacman_db_lock_present || return 1

  ops_warn_pacman_lock
  operation_plan_set_status "$operation_id" "blocked" "lock do pacman encontrado em $(ops_pacman_db_lock_file)"
  return 0
}

ops_run_legacy_pacman_operation() {
  local action="$1"
  shift

  case "$action" in
    upgrade-install)
      retry_interactive_log_only sudo pacman -Syu --needed --noconfirm "$@"
      ;;
    upgrade-full)
      retry_interactive_log_only sudo pacman -Syu --noconfirm
      ;;
    install-needed)
      retry_interactive_log_only sudo pacman -S --needed --noconfirm "$@"
      ;;
    remove-recursive)
      retry_interactive_log_only sudo pacman -Rns --noconfirm "$@"
      ;;
    refresh-databases)
      run_interactive_log_only sudo pacman -Syy --noconfirm
      ;;
    *)
      return 1
      ;;
  esac
}

ops_pacman_operation_executor() {
  local operation_id="$1"
  local action="${OPS_PACMAN_OPERATION_ACTIONS[$operation_id]:-}"
  local packages_text="${OPS_PACMAN_OPERATION_PACKAGES[$operation_id]:-}"
  local packages=()

  if [[ -n "$packages_text" ]]; then
    read -r -a packages <<<"$packages_text"
  fi

  ops_run_legacy_pacman_operation "$action" "${packages[@]}"
}

ops_plan_pacman_operation() {
  local action="$1"
  local description="$2"
  local command_line="$3"
  local target="$4"
  shift 4
  local packages=("$@")
  local packages_label="${packages[*]:-sistema}"
  local operation_id

  operation_id="pacman-$action:$(ops_sanitize_id "$packages_label")"
  OPS_PACMAN_OPERATION_ACTIONS["$operation_id"]="$action"
  OPS_PACMAN_OPERATION_PACKAGES["$operation_id"]="${packages[*]}"

  operation_plan_add \
    "$operation_id" \
    "pacman" \
    "$target" \
    "$description" \
    "high" \
    "" \
    "allow" \
    "ops_pacman_operation_executor" \
    "reexecutar pacman após resolver a causa da falha"
  operation_plan_set_command "$operation_id" "$command_line" "1"

  if ops_block_planned_package_operation_if_locked "$operation_id"; then
    return 2
  fi

  operation_plan_execute "$operation_id"
}

ops_pacman_upgrade_and_install_needed() {
  local packages=("$@")
  local target_label="${packages[*]:-sistema}"

  if ! ops_package_planner_available; then
    ops_run_legacy_pacman_operation upgrade-install "${packages[@]}"
    return $?
  fi

  ops_plan_pacman_operation \
    "upgrade-install" \
    "Instalar pacotes oficiais necessários após atualização" \
