    "$repo_dir"
}

ops_git_checkout_main_from_origin() {
  local repo_dir="$1"

  if ! ops_git_planner_available; then
    ops_run_legacy_git_operation checkout-main-from-origin "$repo_dir"
    return $?
  fi

  ops_plan_git_operation \
    "checkout-main-from-origin" \
    "$repo_dir" \
    "" \
    "0" \
    "Criar main local a partir de origin/main" \
    "$(ops_command_line git -C "$repo_dir" checkout -b main origin/main)" \
    "$repo_dir"
}

ops_git_pull_main_ff_only() {
  local repo_dir="$1"

  if ! ops_git_planner_available; then
    ops_run_legacy_git_operation pull-main-ff-only "$repo_dir"
    return $?
  fi

  ops_plan_git_operation \
    "pull-main-ff-only" \
    "$repo_dir" \
    "" \
    "0" \
    "Atualizar main com fast-forward" \
    "$(ops_command_line git -C "$repo_dir" pull --ff-only origin main)" \
    "$repo_dir"
}

ops_git_update_submodules() {
  local repo_dir="$1"

  if ! ops_git_planner_available; then
    ops_run_legacy_git_operation update-submodules "$repo_dir"
    return $?
  fi

  ops_plan_git_operation \
    "update-submodules" \
    "$repo_dir" \
    "" \
    "0" \
    "Atualizar submódulos git" \
    "$(ops_command_line git -C "$repo_dir" submodule update --init --recursive)" \
    "$repo_dir"
}

ops_git_clone_main() {
  local repo_url="$1"
  local repo_dir="$2"
  local clone_submodules="${3:-0}"
  local clone_args=(clone --branch main --single-branch)

  if [[ "$clone_submodules" == "1" ]]; then
    clone_args+=(--recurse-submodules)
  fi

  clone_args+=("$repo_url" "$repo_dir")
  if ! ops_git_planner_available; then
    ops_run_legacy_git_operation clone-main "$repo_dir" "$repo_url" "$clone_submodules"
    return $?
  fi

  ops_plan_git_operation \
    "clone-main" \
    "$repo_dir" \
    "$repo_url" \
    "$clone_submodules" \
    "Clonar repositório git" \
    "$(ops_command_line git "${clone_args[@]}")" \
    "$repo_dir <- $repo_url"
}
# --- end: scripts/lib/ops/git.sh ---

# --- begin: scripts/lib/ops/github.sh ---
# shellcheck shell=bash

ops_github_planner_available() {
  declare -F operation_plan_add >/dev/null && declare -F operation_plan_execute >/dev/null
}

ops_github_record_direct_operation() {
  local operation_id="$1"
  local target="$2"
  local description="$3"
  local command_line="$4"
  local risk="${5:-medium}"

  ops_github_planner_available || return 1
  operation_plan_add \
    "$operation_id" \
    "github" \
    "$target" \
    "$description" \
    "$risk" \
    "" \
    "allow" \
    "" \
    "repetir comando gh após resolver autenticação ou conectividade" || return 1
  operation_plan_set_command "$operation_id" "$command_line" "0"

  if [[ "${DRY_RUN:-0}" == "1" ]]; then
    operation_plan_set_status "$operation_id" "planned" "dry-run"
    return 2
  fi

  return 0
}

ops_gh_auth_login() {
  local operation_id="github-auth-login:github.com"

  if ops_github_record_direct_operation \
    "$operation_id" \
    "github.com" \
    "Autenticar GitHub CLI" \
    "$(ops_command_line gh auth login --web --git-protocol ssh --scopes admin:public_key)" \
    "medium"; then
    :
  elif [[ "$?" == "2" ]]; then
    return 2
  fi

  run_gh_auth_flow auth login --web --git-protocol ssh --scopes admin:public_key
  local status=$?
  if ops_github_planner_available; then
    if [[ "$status" == "0" ]]; then
      operation_plan_set_status "$operation_id" "succeeded" "executada"
    else
      operation_plan_set_status "$operation_id" "failed" "falha na execução"
    fi
  fi
  return "$status"
}

