# shellcheck shell=bash

declare -Ag OPS_SSH_OPERATION_ACTIONS=()
declare -Ag OPS_SSH_OPERATION_KEY_PATHS=()
declare -Ag OPS_SSH_OPERATION_PUBLIC_PATHS=()
declare -Ag OPS_SSH_OPERATION_COMMENTS=()

ops_ssh_planner_available() {
  declare -F operation_plan_add >/dev/null && declare -F operation_plan_execute >/dev/null
}

ops_run_legacy_ssh_operation() {
  local action="$1"
  local private_key_path="$2"
  local public_key_path="${3:-}"
  local key_comment="${4:-}"

  case "$action" in
    regenerate-public-key)
      ssh-keygen -y -f "$private_key_path" >"$public_key_path"
      ;;
    generate-key-pair)
      ssh-keygen -t ed25519 -C "$key_comment" -f "$private_key_path" -N ""
      ;;
    *)
      return 1
      ;;
  esac
}

ops_ssh_operation_executor() {
  local operation_id="$1"
  local action="${OPS_SSH_OPERATION_ACTIONS[$operation_id]:-}"
  local private_key_path="${OPS_SSH_OPERATION_KEY_PATHS[$operation_id]:-}"
  local public_key_path="${OPS_SSH_OPERATION_PUBLIC_PATHS[$operation_id]:-}"
  local key_comment="${OPS_SSH_OPERATION_COMMENTS[$operation_id]:-}"

  ops_run_legacy_ssh_operation "$action" "$private_key_path" "$public_key_path" "$key_comment"
}

ops_plan_ssh_operation() {
  local action="$1"
  local private_key_path="$2"
  local public_key_path="$3"
  local key_comment="$4"
  local description="$5"
  local command_line="$6"
  local target="$7"
  local operation_id

  operation_id="ssh-$action:$(ops_sanitize_id "$target")"
  OPS_SSH_OPERATION_ACTIONS["$operation_id"]="$action"
  OPS_SSH_OPERATION_KEY_PATHS["$operation_id"]="$private_key_path"
  OPS_SSH_OPERATION_PUBLIC_PATHS["$operation_id"]="$public_key_path"
  OPS_SSH_OPERATION_COMMENTS["$operation_id"]="$key_comment"

  operation_plan_add \
    "$operation_id" \
    "ssh" \
    "$target" \
    "$description" \
    "medium" \
    "" \
    "allow" \
    "ops_ssh_operation_executor" \
    "remover chave gerada manualmente se necessário"
  operation_plan_set_command "$operation_id" "$command_line" "0"

  operation_plan_execute "$operation_id"
}

ops_ssh_regenerate_public_key() {
  local private_key_path="$1"
  local public_key_path="$2"

  if ! ops_ssh_planner_available; then
    ops_run_legacy_ssh_operation regenerate-public-key "$private_key_path" "$public_key_path"
    return $?
  fi

  ops_plan_ssh_operation \
    "regenerate-public-key" \
    "$private_key_path" \
    "$public_key_path" \
    "" \
    "Recriar chave pública SSH local" \
    "$(ops_command_line ssh-keygen -y -f "$private_key_path" '>' "$public_key_path")" \
    "$public_key_path"
}

ops_ssh_generate_key_pair() {
  local key_comment="$1"
  local key_path="$2"

  if ! ops_ssh_planner_available; then
    ops_run_legacy_ssh_operation generate-key-pair "$key_path" "" "$key_comment"
    return $?
  fi

  ops_plan_ssh_operation \
    "generate-key-pair" \
    "$key_path" \
    "${key_path}.pub" \
    "$key_comment" \
    "Gerar par de chaves SSH local" \
    "$(ops_command_line ssh-keygen -t ed25519 -C "$key_comment" -f "$key_path" -N "")" \
    "$key_path"
}
# --- end: scripts/lib/ops/ssh.sh ---

# --- begin: scripts/lib/ops/systemd.sh ---
# shellcheck shell=bash

declare -Ag OPS_SYSTEMD_OPERATION_SCOPES=()
declare -Ag OPS_SYSTEMD_OPERATION_ACTIONS=()
declare -Ag OPS_SYSTEMD_OPERATION_UNITS=()

ops_systemd_planner_available() {
  declare -F operation_plan_add >/dev/null && declare -F operation_plan_execute >/dev/null
}

ops_run_legacy_systemd_operation() {
  local scope="$1"
  local action="$2"
  shift 2

  case "$scope:$action" in
    user:daemon-reload)
      run_log_only systemctl --user daemon-reload
      ;;
    user:start)
      run_log_only systemctl --user start "$@"
      ;;
    system:start)
      run_log_only sudo systemctl start "$@"
      ;;
    system:enable)
      run_log_only sudo systemctl enable "$@"
      ;;
    *)
      return 1
      ;;
  esac
}

ops_systemd_operation_executor() {
  local operation_id="$1"
  local scope="${OPS_SYSTEMD_OPERATION_SCOPES[$operation_id]:-}"
  local action="${OPS_SYSTEMD_OPERATION_ACTIONS[$operation_id]:-}"
  local units_text="${OPS_SYSTEMD_OPERATION_UNITS[$operation_id]:-}"
  local units=()

  if [[ -n "$units_text" ]]; then
    read -r -a units <<<"$units_text"
  fi

  ops_run_legacy_systemd_operation "$scope" "$action" "${units[@]}"
}

ops_plan_systemd_operation() {
  local scope="$1"
  local action="$2"
  local description="$3"
  local command_line="$4"
  local requires_root="$5"
  shift 5
  local units=("$@")
  local units_label="${units[*]:-daemon-reload}"
  local operation_id

  operation_id="systemd-$scope-$action:$(ops_sanitize_id "$units_label")"
  OPS_SYSTEMD_OPERATION_SCOPES["$operation_id"]="$scope"
  OPS_SYSTEMD_OPERATION_ACTIONS["$operation_id"]="$action"
  OPS_SYSTEMD_OPERATION_UNITS["$operation_id"]="${units[*]}"

  operation_plan_add \
    "$operation_id" \
    "systemd" \
    "$units_label" \
    "$description" \
    "medium" \
    "" \
    "allow" \
    "ops_systemd_operation_executor" \
    "verificar unidade e repetir systemctl manualmente"
  operation_plan_set_command "$operation_id" "$command_line" "$requires_root"

  operation_plan_execute "$operation_id"
}

ops_systemctl_user_daemon_reload() {
  if ! ops_systemd_planner_available; then
    ops_run_legacy_systemd_operation user daemon-reload
    return $?
  fi

  ops_plan_systemd_operation \
    "user" \
    "daemon-reload" \
    "Recarregar unidades systemd do usuário" \
    "$(ops_command_line systemctl --user daemon-reload)" \
    "0"
}

ops_systemctl_user_start() {
  local units=("$@")

  if ! ops_systemd_planner_available; then
    ops_run_legacy_systemd_operation user start "${units[@]}"
    return $?
  fi

  ops_plan_systemd_operation \
    "user" \
    "start" \
    "Iniciar unidades systemd do usuário" \
    "$(ops_command_line systemctl --user start "${units[@]}")" \
    "0" \
    "${units[@]}"
}

ops_systemctl_start() {
  local units=("$@")

  if ! ops_systemd_planner_available; then
    ops_run_legacy_systemd_operation system start "${units[@]}"
    return $?
  fi

  ops_plan_systemd_operation \
    "system" \
    "start" \
    "Iniciar unidades systemd do sistema" \
    "$(ops_command_line sudo systemctl start "${units[@]}")" \
    "1" \
    "${units[@]}"
}

ops_systemctl_enable() {
  local units=("$@")

  if ! ops_systemd_planner_available; then
    ops_run_legacy_systemd_operation system enable "${units[@]}"
    return $?
  fi

  ops_plan_systemd_operation \
    "system" \
    "enable" \
    "Habilitar unidades systemd do sistema" \
    "$(ops_command_line sudo systemctl enable "${units[@]}")" \
    "1" \
    "${units[@]}"
}
# --- end: scripts/lib/ops/systemd.sh ---

# --- begin: scripts/lib/repo/manifest/store.sh ---
# shellcheck shell=bash
# shellcheck disable=SC2034

MANAGED_REPO_IDS=()
declare -Ag MANAGED_REPO_DIRS=()
declare -Ag MANAGED_REPO_HTTPS_URLS=()
declare -Ag MANAGED_REPO_SSH_URLS=()
declare -Ag MANAGED_REPO_LABELS=()
declare -Ag MANAGED_REPO_ENVIRONMENT_FLAGS=()
declare -Ag MANAGED_REPO_CLONE_SUBMODULE_FLAGS=()
declare -Ag MANAGED_REPO_PREFERRED_TRANSPORTS=()

managed_repo_manifest_reset() {
  MANAGED_REPO_IDS=()
  MANAGED_REPO_DIRS=()
  MANAGED_REPO_HTTPS_URLS=()
  MANAGED_REPO_SSH_URLS=()
  MANAGED_REPO_LABELS=()
  MANAGED_REPO_ENVIRONMENT_FLAGS=()
  MANAGED_REPO_CLONE_SUBMODULE_FLAGS=()
  MANAGED_REPO_PREFERRED_TRANSPORTS=()
}
# --- end: scripts/lib/repo/manifest/store.sh ---

# --- begin: scripts/lib/repo/manifest/registration.sh ---
# shellcheck shell=bash

register_managed_repo() {
  local repo_id="$1"
  shift

  local assignment=""
  local repo_dir=""
  local https_url=""
  local ssh_url=""
  local repo_label=""
  local environment_repo=""
  local clone_submodules="0"
  local preferred_transport="auto"

  for assignment in "$@"; do
    case "$assignment" in
      dir=*)
        repo_dir="${assignment#*=}"
        ;;
      https_url=*)
        https_url="${assignment#*=}"
        ;;
      ssh_url=*)
        ssh_url="${assignment#*=}"
        ;;
      label=*)
        repo_label="${assignment#*=}"
        ;;
      environment=*)
        environment_repo="${assignment#*=}"
        ;;
      clone_submodules=*)
        clone_submodules="${assignment#*=}"
        ;;
      preferred_transport=*)
        preferred_transport="${assignment#*=}"
        ;;
      *)
        printf 'Erro: metadado de repositório desconhecido para %s: %s\n' "$repo_id" "$assignment" >&2
        return 1
        ;;
    esac
  done

  if [[ -z "$repo_id" || -z "$repo_dir" || -z "$https_url" || -z "$ssh_url" || \
    -z "$repo_label" || -z "$environment_repo" ]]; then
    printf 'Erro: repositório gerenciado incompleto: %s\n' "${repo_id:-indefinido}" >&2
    return 1
  fi

  case "$clone_submodules" in
    0|1)
      ;;
    *)
      printf 'Erro: clone_submodules inválido para %s: %s\n' "$repo_id" "$clone_submodules" >&2
      return 1
      ;;
  esac

  case "$preferred_transport" in
    auto|https|ssh)
      ;;
    *)
      printf 'Erro: preferred_transport inválido para %s: %s\n' "$repo_id" "$preferred_transport" >&2
      return 1
      ;;
  esac

  MANAGED_REPO_IDS+=("$repo_id")
  MANAGED_REPO_DIRS["$repo_id"]="$repo_dir"
  MANAGED_REPO_HTTPS_URLS["$repo_id"]="$https_url"
  MANAGED_REPO_SSH_URLS["$repo_id"]="$ssh_url"
  MANAGED_REPO_LABELS["$repo_id"]="$repo_label"
  MANAGED_REPO_ENVIRONMENT_FLAGS["$repo_id"]="$environment_repo"
  MANAGED_REPO_CLONE_SUBMODULE_FLAGS["$repo_id"]="$clone_submodules"
  MANAGED_REPO_PREFERRED_TRANSPORTS["$repo_id"]="$preferred_transport"
}
# --- end: scripts/lib/repo/manifest/registration.sh ---

# --- begin: scripts/lib/repo/manifest/definitions.sh ---
