# --- end: scripts/lib/repo/manifest/definitions.sh ---

# --- begin: scripts/lib/repo/manifest/queries.sh ---
# shellcheck shell=bash

managed_repo_id_for_dir() {
  local expected_repo_dir="$1"
  local repo_id

  for repo_id in "${MANAGED_REPO_IDS[@]}"; do
    if [[ "${MANAGED_REPO_DIRS[$repo_id]}" == "$expected_repo_dir" ]]; then
      printf '%s\n' "$repo_id"
      return 0
    fi
  done

  return 1
}

managed_repo_expected_https_origin_url() {
  local repo_id=""

  repo_id="$(managed_repo_id_for_dir "$1")" || return 1
  printf '%s\n' "${MANAGED_REPO_HTTPS_URLS[$repo_id]}"
}

managed_repo_expected_ssh_origin_url() {
  local repo_id=""

  repo_id="$(managed_repo_id_for_dir "$1")" || return 1
  printf '%s\n' "${MANAGED_REPO_SSH_URLS[$repo_id]}"
}

managed_environment_repo_dirs() {
  local repo_id

  for repo_id in "${MANAGED_REPO_IDS[@]}"; do
    [[ "${MANAGED_REPO_ENVIRONMENT_FLAGS[$repo_id]}" == "1" ]] || continue
    printf '%s\n' "${MANAGED_REPO_DIRS[$repo_id]}"
  done
}

managed_repo_clone_submodules() {
  local repo_id=""

  repo_id="$(managed_repo_id_for_dir "$1")" || return 1
  printf '%s\n' "${MANAGED_REPO_CLONE_SUBMODULE_FLAGS[$repo_id]:-0}"
}

managed_repo_preferred_transport() {
  local repo_id=""

  repo_id="$(managed_repo_id_for_dir "$1")" || return 1
  printf '%s\n' "${MANAGED_REPO_PREFERRED_TRANSPORTS[$repo_id]:-auto}"
}

managed_repo_display_name() {
  local repo_id=""

  repo_id="$(managed_repo_id_for_dir "$1")" || {
    basename "$1"
    return 0
  }
  printf '%s\n' "${MANAGED_REPO_LABELS[$repo_id]}"
}
# --- end: scripts/lib/repo/manifest/queries.sh ---

# --- begin: scripts/lib/repo/origin/status.sh ---
# shellcheck shell=bash

get_repo_branch() {
  local repo_dir="$1"
  local branch_name=""

  if ! git -C "$repo_dir" rev-parse --is-inside-work-tree >/dev/null 2>&1; then
    return 1
  fi

  branch_name="$(git -C "$repo_dir" symbolic-ref --quiet --short HEAD 2>/dev/null || true)"
  if [[ -n "$branch_name" ]]; then
    printf '%s\n' "$branch_name"
    return 0
  fi

  branch_name="$(git -C "$repo_dir" rev-parse --short HEAD 2>/dev/null || true)"
  [[ -n "$branch_name" ]] || return 1
  printf 'detached@%s\n' "$branch_name"
}

current_repo_origin_status() {
  local repo_dir="$1"
  local current_origin_url=""
  local managed_https_url=""
  local managed_ssh_url=""

  current_origin_url="$(git -C "$repo_dir" remote get-url origin 2>/dev/null || true)"
  managed_https_url="$(managed_repo_expected_https_origin_url "$repo_dir" 2>/dev/null || true)"
  managed_ssh_url="$(managed_repo_expected_ssh_origin_url "$repo_dir" 2>/dev/null || true)"

  if [[ -z "$current_origin_url" ]]; then
    printf '%s\n' "ausente"
    return 0
  fi

  if [[ "$current_origin_url" == "$REPO_SSH_URL" || ( -n "$managed_ssh_url" && "$current_origin_url" == "$managed_ssh_url" ) ]]; then
    printf '%s\n' "ssh"
    return 0
  fi

  if [[ "$current_origin_url" == "$REPO_HTTPS_URL" || ( -n "$managed_https_url" && "$current_origin_url" == "$managed_https_url" ) ]]; then
    printf '%s\n' "https"
    return 0
  fi

  printf '%s\n' "personalizado"
}

current_repo_commit_short() {
  local repo_dir="$1"
  local commit_hash=""

  commit_hash="$(git -C "$repo_dir" rev-parse --short HEAD 2>/dev/null || true)"
  [[ -n "$commit_hash" ]] || {
    printf '%s\n' "indisponível"
    return 0
  }

  printf '%s\n' "$commit_hash"
}
# --- end: scripts/lib/repo/origin/status.sh ---

# --- begin: scripts/lib/repo/origin/remote.sh ---
# shellcheck shell=bash

ensure_repo_origin_remote() {
  local repo_dir="$1"
  local desired_origin_url="${2:-$REPO_HTTPS_URL}"
  local current_origin_url=""
  local allowed_origin_urls=()
  local managed_https_url=""
  local managed_ssh_url=""
  local allowed_origin_url=""
  local matches_allowed_origin=1

  current_origin_url="$(git -C "$repo_dir" remote get-url origin 2>/dev/null || true)"

  if [[ -z "$current_origin_url" ]]; then
    ops_git_remote_add_origin "$repo_dir" "$desired_origin_url"
    return
  fi

  allowed_origin_urls=("$REPO_HTTPS_URL" "$REPO_SSH_URL")
  managed_https_url="$(managed_repo_expected_https_origin_url "$repo_dir" 2>/dev/null || true)"
  managed_ssh_url="$(managed_repo_expected_ssh_origin_url "$repo_dir" 2>/dev/null || true)"
  [[ -n "$managed_https_url" ]] && allowed_origin_urls+=("$managed_https_url")
  [[ -n "$managed_ssh_url" ]] && allowed_origin_urls+=("$managed_ssh_url")

  for allowed_origin_url in "${allowed_origin_urls[@]}"; do
    if [[ "$current_origin_url" == "$allowed_origin_url" ]]; then
      matches_allowed_origin=0
      break
    fi
  done

  if [[ "$matches_allowed_origin" != "0" ]]; then
    announce_detail "Foi detectado um remoto origin personalizado em $repo_dir. A configuração atual será mantida."
    return
  fi

  if [[ "$current_origin_url" != "$desired_origin_url" ]]; then
    ops_git_remote_set_origin "$repo_dir" "$desired_origin_url"
  fi
}

managed_repo_origin_matches_expected() {
  local repo_dir="$1"
  local current_origin_url=""
  local expected_https_url=""
  local expected_ssh_url=""

  current_origin_url="$(git -C "$repo_dir" remote get-url origin 2>/dev/null || true)"
  expected_https_url="$(managed_repo_expected_https_origin_url "$repo_dir" 2>/dev/null || true)"
  expected_ssh_url="$(managed_repo_expected_ssh_origin_url "$repo_dir" 2>/dev/null || true)"
  [[ -n "$current_origin_url" && -n "$expected_https_url" && -n "$expected_ssh_url" ]] || return 1

  [[ "$current_origin_url" == "$expected_https_url" || "$current_origin_url" == "$expected_ssh_url" ]]
}
# --- end: scripts/lib/repo/origin/remote.sh ---

# --- begin: scripts/lib/repo/origin/transport.sh ---
# shellcheck shell=bash

git_ssh_transport_ready() {
  local repo_url="$1"

  [[ -n "$repo_url" ]] || return 1
  command -v git >/dev/null 2>&1 || return 1

  GIT_SSH_COMMAND='ssh -o BatchMode=yes -o StrictHostKeyChecking=accept-new' \
    git ls-remote "$repo_url" HEAD >/dev/null 2>&1
}
# --- end: scripts/lib/repo/origin/transport.sh ---

# --- begin: scripts/lib/repo/origin/managed.sh ---
# shellcheck shell=bash

managed_repo_preferred_origin_url() {
  local repo_dir="$1"
  local https_url=""
  local ssh_url=""
  local preferred_transport=""

  https_url="$(managed_repo_expected_https_origin_url "$repo_dir" 2>/dev/null || true)"
  ssh_url="$(managed_repo_expected_ssh_origin_url "$repo_dir" 2>/dev/null || true)"
  preferred_transport="$(managed_repo_preferred_transport "$repo_dir" 2>/dev/null || true)"
  [[ -n "$https_url" && -n "$ssh_url" ]] || return 1

  case "$preferred_transport" in
    https)
      printf '%s\n' "$https_url"
      return 0
      ;;
    ssh)
      printf '%s\n' "$ssh_url"
      return 0
      ;;
  esac

  if github_ssh_expected && git_ssh_transport_ready "$ssh_url"; then
    printf '%s\n' "$ssh_url"
    return 0
  fi

  printf '%s\n' "$https_url"
}

ensure_managed_repo_origin_remote() {
  local repo_dir="$1"
  local desired_origin_url=""

  desired_origin_url="$(managed_repo_preferred_origin_url "$repo_dir" 2>/dev/null || true)"
  [[ -n "$desired_origin_url" ]] || return 1

  ensure_repo_origin_remote "$repo_dir" "$desired_origin_url"
}

ensure_managed_repo_origin_ssh() {
  local repo_dir="$1"
  local desired_origin_url=""

  desired_origin_url="$(managed_repo_expected_ssh_origin_url "$repo_dir" 2>/dev/null || true)"
  [[ -n "$desired_origin_url" ]] || return 1

  ensure_repo_origin_remote "$repo_dir" "$desired_origin_url"
}

reconcile_managed_repo_origin_ssh() {
  local repo_dir="$1"
  local preferred_transport=""

  [[ -d "$repo_dir/.git" ]] || return 2
  preferred_transport="$(managed_repo_preferred_transport "$repo_dir" 2>/dev/null || true)"
  [[ "$preferred_transport" != "https" ]] || return 2

  if ! managed_repo_origin_matches_expected "$repo_dir"; then
    announce_detail "Foi detectado um remoto origin personalizado em $repo_dir. A configuração atual será mantida."
    return 2
  fi

  if ! ensure_managed_repo_origin_ssh "$repo_dir"; then
    return 1
  fi

  return 0
}

easyeffects_preset_origin_matches() {
  managed_repo_origin_matches_expected "$EASY_EFFECTS_PRESET_DIR"
}
# --- end: scripts/lib/repo/origin/managed.sh ---

# --- begin: scripts/lib/repo/relocation.sh ---
# shellcheck shell=bash

legacy_install_dir_path() {
  printf '%s\n' "$REPOSITORIES_DIR/arch-postinstall-apps"
}

relocate_managed_install_repo() {
  local legacy_install_dir=""

  legacy_install_dir="$(legacy_install_dir_path)"
  [[ "$legacy_install_dir" != "$INSTALL_DIR" ]] || return 3
  [[ -d "$legacy_install_dir" ]] || return 2

  if [[ -e "$INSTALL_DIR" ]]; then
    announce_warning "O clone gerenciado legado em $legacy_install_dir não foi movido porque $INSTALL_DIR já existe."
    return 2
  fi

  if [[ ! -d "$legacy_install_dir/.git" ]]; then
    announce_warning "$legacy_install_dir existe, mas não é um repositório git gerenciado."
    return 2
  fi

  mkdir -p "$(dirname "$INSTALL_DIR")"
  announce_detail "Movendo clone gerenciado para $INSTALL_DIR..."
  if mv "$legacy_install_dir" "$INSTALL_DIR"; then
    return 0
  fi

  announce_warning "Não foi possível mover o clone gerenciado para $INSTALL_DIR."
  return 1
}

directory_is_git_repository() {
  local dir_path="$1"

  git -C "$dir_path" rev-parse --is-inside-work-tree >/dev/null 2>&1
}

home_repo_relocation_allowed() {
  local repo_dir="$1"
  local repo_name=""

  repo_name="$(basename "$repo_dir")"
  case "$repo_name" in
    Backups|Codex|Dots|EasyEffects-Preset|Pictures|Projects|Repositories|Videos)
      return 1
      ;;
  esac

  return 0
}

collect_loose_home_git_repositories() {
  local array_name="$1"
  local candidate
  local nullglob_was_enabled=0
  # shellcheck disable=SC2178
  declare -n target_repositories="$array_name"

  target_repositories=()

  if shopt -q nullglob; then
    nullglob_was_enabled=1
  fi
  shopt -s nullglob

  for candidate in "$HOME"/*; do
    [[ -d "$candidate" && ! -L "$candidate" ]] || continue
    home_repo_relocation_allowed "$candidate" || continue
    directory_is_git_repository "$candidate" || continue
    target_repositories+=("$candidate")
  done

  if [[ "$nullglob_was_enabled" != "1" ]]; then
    shopt -u nullglob
  fi
}

relocate_loose_home_git_repository() {
  local source_repo_dir="$1"
  local repo_name=""
  local target_repo_dir=""

  repo_name="$(basename "$source_repo_dir")"
  target_repo_dir="$REPOSITORIES_DIR/$repo_name"

  if [[ -e "$target_repo_dir" ]]; then
    announce_warning "O repositório '$repo_name' em $HOME não foi movido porque $target_repo_dir já existe."
    return 2
  fi

  announce_detail "Movendo repositório git para $target_repo_dir..."
  if mv "$source_repo_dir" "$target_repo_dir"; then
    return 0
  fi

  announce_warning "Não foi possível mover o repositório '$repo_name' para $target_repo_dir."
  return 1
}
# --- end: scripts/lib/repo/relocation.sh ---

# --- begin: scripts/lib/repo/sync.sh ---
# shellcheck shell=bash

managed_repo_is_dirty() {
  local repo_dir="$1"

  ! git -C "$repo_dir" diff --quiet --no-ext-diff || \
    ! git -C "$repo_dir" diff --cached --quiet --no-ext-diff || \
    [[ -n "$(git -C "$repo_dir" status --porcelain --untracked-files=normal)" ]]
}

sync_git_main_branch() {
  local repo_dir="$1"
  local repo_label="$2"
  local sync_mode="${3:-strict}"
  local fetched_origin=0

  if ops_git_fetch_origin "$repo_dir"; then
    fetched_origin=1
  elif [[ "$sync_mode" == "bootstrap" ]]; then
    announce_warning "Falha ao buscar atualizações de origin. O script tentará usar a cópia local."
  else
    announce_warning "Não foi possível buscar atualizações de $repo_label."
    return 1
  fi

  if git -C "$repo_dir" show-ref --verify --quiet "refs/heads/main"; then
    if ! ops_git_checkout_main "$repo_dir"; then
      if [[ "$sync_mode" == "bootstrap" ]]; then
        announce_error "Não foi possível trocar para a branch local 'main'."
      else
        announce_warning "Não foi possível trocar $repo_label para a branch 'main'."
      fi
      return 1
    fi
  elif git -C "$repo_dir" show-ref --verify --quiet "refs/remotes/origin/main"; then
    if ! ops_git_checkout_main_from_origin "$repo_dir"; then
      if [[ "$sync_mode" == "bootstrap" ]]; then
        announce_error "Não foi possível criar a branch local 'main' a partir de origin."
      else
        announce_warning "Não foi possível criar a branch local 'main' de $repo_label."
      fi
      return 1
    fi
  elif [[ "$sync_mode" == "bootstrap" && "$fetched_origin" == "0" ]]; then
    announce_error "Não foi possível atualizar origin e a branch 'main' não existe localmente."
    announce_error "Verifique acesso ao GitHub ou recupere um clone local válido."
    return 1
  else
    if [[ "$sync_mode" == "bootstrap" ]]; then
      announce_error "Branch 'main' não encontrada no repositório local nem em origin."
    else
      announce_warning "A branch 'main' não foi encontrada em $repo_label."
    fi
    return 1
  fi

  if [[ "$sync_mode" == "bootstrap" && "$fetched_origin" == "0" ]]; then
    announce_warning "O 'git pull' será ignorado porque o fetch de origin falhou. O script continuará com a branch local."
    return 0
  fi

  if ops_git_pull_main_ff_only "$repo_dir"; then
    return 0
  fi

  if [[ "$sync_mode" == "bootstrap" ]]; then
    announce_warning "Falha ao atualizar 'main' com 'git pull --ff-only'. O script continuará com a cópia atual."
    return 0
  fi

  announce_warning "Não foi possível atualizar $repo_label com 'git pull --ff-only'."
  return 1
}

sync_managed_repo() {
  local repo_dir="$1"
  local repo_label=""
  local previous_commit=""
  local current_commit=""
  local clone_origin_url=""
  local clone_submodules="0"
  local label_suffix=""

  repo_label="$(managed_repo_display_name "$repo_dir")"
  clone_submodules="$(managed_repo_clone_submodules "$repo_dir" 2>/dev/null || printf '0\n')"
  label_suffix="do repositório $repo_label"

  if ! command -v git >/dev/null 2>&1; then
    announce_warning "O git não está disponível para sincronizar $label_suffix."
    return 1
  fi

  if [[ -d "$repo_dir/.git" ]]; then
    previous_commit="$(git -C "$repo_dir" rev-parse HEAD 2>/dev/null || true)"

    if ! managed_repo_origin_matches_expected "$repo_dir"; then
      announce_warning "O diretório $repo_dir já é um repositório git com origin diferente. A sincronização será ignorada."
      return 2
    fi

    if managed_repo_is_dirty "$repo_dir"; then
      announce_warning "O repositório em $repo_dir tem alterações locais. A atualização automática será ignorada."
      return 2
    fi

    if ! ensure_managed_repo_origin_remote "$repo_dir"; then
      announce_warning "Não foi possível ajustar o remoto de $label_suffix."
      return 1
    fi

    announce_detail "Atualizando $label_suffix..."
    if ! sync_git_main_branch "$repo_dir" "$label_suffix"; then
      return 1
    fi
    if [[ "$clone_submodules" == "1" ]]; then
      announce_detail "Atualizando submódulos $label_suffix..."
      if ! ops_git_update_submodules "$repo_dir"; then
        announce_warning "Não foi possível atualizar os submódulos de $repo_label."
        return 1
      fi
    fi

    current_commit="$(git -C "$repo_dir" rev-parse HEAD 2>/dev/null || true)"
    if [[ -n "$previous_commit" && "$previous_commit" == "$current_commit" ]]; then
      return 3
    fi

    return 0
  fi

  if [[ -e "$repo_dir" && -n "$(find "$repo_dir" -mindepth 1 -maxdepth 1 2>/dev/null)" ]]; then
    announce_warning "$repo_dir já existe e não está vazio. O clone de $label_suffix será ignorado."
    return 2
  fi

  announce_detail "Clonando $label_suffix em $repo_dir..."
  clone_origin_url="$(managed_repo_preferred_origin_url "$repo_dir" 2>/dev/null || true)"
  if [[ -z "$clone_origin_url" ]]; then
    announce_warning "Não foi possível definir a URL de clone de $label_suffix."
    return 1
  fi

  if ops_git_clone_main "$clone_origin_url" "$repo_dir" "$clone_submodules"; then
    return 0
  fi

  announce_warning "Não foi possível clonar $label_suffix."
  return 1
}
# --- end: scripts/lib/repo/sync.sh ---

# --- begin: scripts/bootstrap/repo-sync.sh ---
# shellcheck shell=bash

sync_repo() {
  local current_branch=""
  local clone_origin_url=""

  mkdir -p "$(dirname "$INSTALL_DIR")"

  relocate_managed_install_repo || true

  if [[ -d "$INSTALL_DIR/.git" ]]; then
    announce_detail "Atualizando clone gerenciado..."
    if managed_repo_is_dirty "$INSTALL_DIR"; then
      current_branch="$(get_repo_branch "$INSTALL_DIR" 2>/dev/null || true)"
      if [[ -n "$current_branch" && "$current_branch" != "main" ]]; then
        announce_error "O clone gerenciado está com mudanças locais na branch '$current_branch'."
        announce_error "Não dá para executar com segurança a branch 'main' sem limpar ou mover essas mudanças."
        return 1
      fi

      announce_warning "O repositório local tem alterações. A atualização automática será ignorada."
      return 0
    fi

    if ! ensure_managed_repo_origin_remote "$INSTALL_DIR"; then
      announce_error "Não foi possível ajustar o remoto origin do clone gerenciado."
      return 1
    fi

    sync_git_main_branch "$INSTALL_DIR" "clone gerenciado" "bootstrap"
    return
  fi

  if [[ -e "$INSTALL_DIR" ]]; then
    announce_error "$INSTALL_DIR já existe e não é um repositório git."
    return 1
  fi

  announce_detail "Clonando repositório pela primeira vez..."
  clone_origin_url="$(managed_repo_preferred_origin_url "$INSTALL_DIR" 2>/dev/null || true)"
  if [[ -z "$clone_origin_url" ]]; then
    announce_error "Não foi possível definir a URL de clone do repositório principal."
    return 1
  fi

  if ! ops_git_clone_main "$clone_origin_url" "$INSTALL_DIR"; then
    announce_error "Falha ao clonar 'main' de $clone_origin_url."
    announce_error "Verifique acesso ao GitHub e se a branch existe no remoto."
    return 1
  fi
}
# --- end: scripts/bootstrap/repo-sync.sh ---

# --- begin: scripts/bootstrap/config.sh ---
# shellcheck shell=bash
# shellcheck disable=SC2034

readonly -a BOOTSTRAP_REMOTE_PACKAGES=(
  ca-certificates
  git
  curl
  tar
)
# --- end: scripts/bootstrap/config.sh ---

# --- begin: scripts/bootstrap/steps/system.sh ---
# shellcheck shell=bash

bootstrap_validate_environment_step() {
  validate_execution_environment_step "bootstrap" "O ambiente de bootstrap foi validado."
}
# --- end: scripts/bootstrap/steps/system.sh ---

# --- begin: scripts/bootstrap/steps/packages.sh ---
# shellcheck shell=bash
# shellcheck disable=SC2034

bootstrap_check_dependencies_step() {
  local array_name="$1"
  # shellcheck disable=SC2178
  declare -n missing_packages="$array_name"

  step_result_reset

  if ((${#missing_packages[@]} == 0)); then
    announce_detail "As dependências iniciais já estão disponíveis."
    step_result_success "As dependências iniciais já estavam disponíveis."
    return 0
  fi

  announce_detail "${#missing_packages[@]} dependência(s) inicial(is) ainda não instalada(s)."
  step_result_success "As dependências iniciais foram avaliadas."
}

bootstrap_install_dependencies_step() {
  local array_name="${1:-BOOTSTRAP_MISSING_PACKAGES}"
  # shellcheck disable=SC2178
  declare -n missing_packages="$array_name"

  step_result_reset

  if ((${#missing_packages[@]} == 0)); then
    announce_detail "As dependências iniciais já estão disponíveis. Etapa ignorada."
    step_result_skipped "As dependências iniciais já estavam disponíveis."
    return 0
  fi

  if ops_pacman_upgrade_and_install_needed "${missing_packages[@]}"; then
    BOOTSTRAP_SYSTEM_UPDATED=1
    step_result_success "As dependências iniciais foram instaladas."
    return 0
  fi

  step_result_hard_fail "Não foi possível instalar as dependências iniciais."
}
# --- end: scripts/bootstrap/steps/packages.sh ---

# --- begin: scripts/bootstrap/steps/repo.sh ---
# shellcheck shell=bash

bootstrap_sync_repo_step() {
  step_result_reset

  if ! require_command git; then
    step_result_hard_fail "O comando 'git' é obrigatório para sincronizar o repositório."
    return 0
  fi

  if ! require_command curl; then
    step_result_hard_fail "O comando 'curl' é obrigatório para sincronizar o repositório."
    return 0
  fi

  if ! require_command tar; then
    step_result_hard_fail "O comando 'tar' é obrigatório para sincronizar o repositório."
    return 0
  fi

  if sync_repo; then
    step_result_success "O repositório gerenciado foi sincronizado."
    return 0
  fi

  step_result_hard_fail "Não foi possível sincronizar o repositório gerenciado."
}
# --- end: scripts/bootstrap/steps/repo.sh ---

# --- begin: scripts/bootstrap/entrypoint.sh ---
# shellcheck shell=bash
# shellcheck disable=SC2034
# shellcheck source-path=SCRIPTDIR
SELF_PATH="${BASH_SOURCE[0]:-$0}"
BOOTSTRAP_SCRIPT_DIR="$(cd "$(dirname "$SELF_PATH")" && pwd)"

resolve_local_main() {
  local candidate=""

  for candidate in \
    "$BOOTSTRAP_SCRIPT_DIR/scripts/install/main.sh" \
    "$BOOTSTRAP_SCRIPT_DIR/../scripts/install/main.sh"; do
    if [[ -f "$candidate" ]]; then
      printf '%s\n' "$candidate"
      return 0
    fi
  done

  return 1
}

LOCAL_MAIN="$(resolve_local_main 2>/dev/null || true)"
if [[ -n "$LOCAL_MAIN" ]]; then
  exec bash "$LOCAL_MAIN" "$@"
fi

BOOTSTRAP_MISSING_PACKAGES=()
BOOTSTRAP_SYSTEM_UPDATED=0

cleanup_paths=()
step_counter=0
step_open=0
step_total=0
STEP_RESULT_STATUS=""
STEP_RESULT_MESSAGE=""

init_output_styles

handle_bootstrap_step_result_or_exit() {
  case "${STEP_RESULT_STATUS:-}" in
    success|skipped|"")
      return 0
      ;;
    hard_fail)
      if [[ -n "${STEP_RESULT_MESSAGE:-}" ]]; then
        announce_error "$STEP_RESULT_MESSAGE"
      fi
      exit 1
      ;;
    *)
      announce_error "Resultado de etapa desconhecido no bootstrap: ${STEP_RESULT_STATUS:-indefinido}"
      exit 1
      ;;
  esac
}

main() {
  local context_status=0

  load_bootstrap_invocation_context "$@" || context_status=$?
  if (( context_status == CLI_HELP_REQUESTED_STATUS )); then
    exit 0
  fi
  if (( context_status != 0 )); then
    exit "$context_status"
  fi

  validate_managed_paths || exit 1
  trap cleanup EXIT

  ensure_not_root || exit 1
  acquire_lock || exit 1
  collect_missing_packages BOOTSTRAP_MISSING_PACKAGES "${BOOTSTRAP_REMOTE_PACKAGES[@]}"
  define_bootstrap_pipeline BOOTSTRAP_MISSING_PACKAGES
  set_step_total "$(pipeline_count_steps_for_mode bootstrap)"
  run_pipeline_steps "bootstrap" "handle_bootstrap_step_result_or_exit"

  exec_runtime_with_invocation_context "$INSTALL_DIR/scripts/install/main.sh"
}

main "$@"
# --- end: scripts/bootstrap/entrypoint.sh ---
